namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data
        _notifications.AddRange(new[]
        {
            MakeNotification("Welcome to the app!"),
            MakeNotification("Your profile has been set up."),
            MakeNotification("New feature: dark mode is now available."),
        });
    }

    /// <summary>Returns all notifications available at this moment.</summary>
    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.ToList());
        }
    }

    /// <summary>Returns only notifications with an Id greater than <paramref name="sinceId"/>.</summary>
    public Task<List<Notification>> GetNotificationsSinceAsync(int sinceId)
    {
        lock (_lock)
        {
            var newer = _notifications.Where(n => n.Id > sinceId).ToList();

            // Simulate new notifications arriving occasionally
            if (Random.Shared.Next(3) == 0)
            {
                var fresh = MakeNotification(PickRandomMessage());
                _notifications.Add(fresh);
                newer.Add(fresh);
            }

            return Task.FromResult(newer);
        }
    }

    private Notification MakeNotification(string message)
    {
        var n = new Notification(_nextId++, message, DateTime.UtcNow);
        return n;
    }

    private static string PickRandomMessage()
    {
        string[] messages =
        [
            "You have a new follower!",
            "Your report is ready to download.",
            "Scheduled maintenance tonight at 11 PM.",
            "Someone commented on your post.",
            "Your subscription renews soon.",
            "A new update is available.",
        ];
        return messages[Random.Shared.Next(messages.Length)];
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using NotificationsApp.Services
@inject NotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (notifications is not null)
    {
        <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
    }
</h1>

@if (notifications is null)
{
    <p><em>Loading...</em></p>
}
else if (notifications.Count == 0)
{
    <p>No notifications yet.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>
                    <strong>@n.Message</strong>
                    <br />
                    <small class="text-muted">@n.Timestamp.ToString("g")</small>
                </div>
                <span class="badge bg-secondary rounded-pill">#@n.Id</span>
            </li>
        }
    </ul>
}

@code {
    private List<Notification>? notifications;
    private CancellationTokenSource? _cts;

    [PersistentState]
    public List<Notification>? PersistedNotifications { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // Restore from prerender state if available; otherwise load from service.
        // This avoids a duplicate fetch when the interactive runtime attaches.
        PersistedNotifications ??= await NotificationService.GetNotificationsAsync();
        notifications = PersistedNotifications;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // The page is now interactive — start the polling loop.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);

                var lastId = notifications?.Count > 0
                    ? notifications.Max(n => n.Id)
                    : 0;

                var newer = await NotificationService.GetNotificationsSinceAsync(lastId);

                if (newer.Count > 0)
                {
                    notifications ??= new();
                    notifications.AddRange(newer);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (TaskCanceledException)
            {
                break;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

