+<h1>
+    Notifications
+    @if (notifications is not null)
+    {
+        <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
+    }
+</h1>
+
+@if (notifications is null)
+{
+    <p><em>Loading...</em></p>
+}
+else if (notifications.Count == 0)
+{
+    <p>No notifications yet.</p>
+}
+else
+{
+    <ul class="list-group">
+        @foreach (var n in notifications)
+        {
+            <li class="list-group-item d-flex justify-content-between align-items-start">
+                <div>
+                    <strong>@n.Message</strong>
+                    <br />
+                    <small class="text-muted">@n.Timestamp.ToString("g")</small>
+                </div>
+                <span class="badge bg-secondary rounded-pill">#@n.Id</span>
+            </li>
+        }
+    </ul>
+}
+
+@code {
+    private List<Notification>? notifications;
+    private CancellationTokenSource? _cts;
+
+    [PersistentState]
+    public List<Notification>? PersistedNotifications { get; set; }
+
+    protected override async Task OnInitializedAsync()
+    {
+        // Restore from prerender state if available; otherwise load from service.
+        // This avoids a duplicate fetch when the interactive runtime attaches.
+        PersistedNotifications ??= await NotificationService.GetNotificationsAsync();
+        notifications = PersistedNotifications;
+    }
+
+    protected override void OnAfterRender(bool firstRender)
+    {
+        if (firstRender)
+        {
+            // The page is now interactive — start the polling loop.
+            _cts = new CancellationTokenSource();
+            _ = PollForNotificationsAsync(_cts.Token);
+        }
+    }
+
+    private async Task PollForNotificationsAsync(CancellationToken ct)
+    {
+        while (!ct.IsCancellationRequested)
+        {
+            try
+            {
+                await Task.Delay(TimeSpan.FromSeconds(5), ct);
+
+                var lastId = notifications?.Count > 0
+                    ? notifications.Max(n => n.Id)
+                    : 0;
+
+                var newer = await NotificationService.GetNotificationsSinceAsync(lastId);
+
+                if (newer.Count > 0)
+                {
+                    notifications ??= new();
+                    notifications.AddRange(newer);
+                    await InvokeAsync(StateHasChanged);
+                }
+            }
+            catch (TaskCanceledException)
+            {
+                break;
+            }
+        }
+    }
+
+    public void Dispose()
+    {
+        _cts?.Cancel();
+        _cts?.Dispose();
+    }
+}
+

