namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        _notifications.AddRange(new[]
        {
            MakeNotification("Welcome to the app!"),
            MakeNotification("Your profile has been set up."),
            MakeNotification("New feature: dark mode is now available."),
        });
    }

    /// <summary>Returns all notifications available at this moment.</summary>
    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.ToList());
        }
    }

    /// <summary>Returns only notifications with an Id greater than <paramref name="sinceId"/>.</summary>
    public Task<List<Notification>> GetNotificationsSinceAsync(int sinceId)
    {
        lock (_lock)
        {
            var newer = _notifications.Where(n => n.Id > sinceId).ToList();

            // Simulate new notifications arriving occasionally
            if (Random.Shared.Next(3) == 0)
            {
                var fresh = MakeNotification(PickRandomMessage());
                _notifications.Add(fresh);
                newer.Add(fresh);
            }

            return Task.FromResult(newer);
        }
    }

    private Notification MakeNotification(string message)
    {
        var n = new Notification(_nextId++, message, DateTime.UtcNow);
        return n;
    }

    private static string PickRandomMessage()
    {
        string[] messages =
        [
            "You have a new follower!",
            "Your report is ready to download.",
            "Scheduled maintenance tonight at 11 PM.",
            "Someone commented on your post.",
            "Your subscription renews soon.",
            "A new update is available.",
        ];
        return messages[Random.Shared.Next(messages.Length)];
    }
}

